package javapackage;

public class BreakStatement {

	public static void main(String[] args) {
		// TODO Auto-generated method stub

		for (int i=1; i < 10; i++) {
			// If statement
			if (i == 5) {
				break; // breaking the loop
			}
	 System.out.println(i);
	}
		
		System.out.println("control come out from loop");
}
}


